class Solution:
    def minOperations(self, grid, x):
        flat = [v for row in grid for v in row]
        r0 = flat[0] % x
        for v in flat:
            if v % x != r0:
                return -1
        best = None
        for target in flat:
            cost = sum(abs(v - target) // x for v in flat)
            if best is None or cost < best:
                best = cost
        return best

