class Solution:
    def minOperations(self, grid, x):
        flat = [v for row in grid for v in row]
        r0 = flat[0] % x
        for v in flat:
            if v % x != r0:
                return -1
        flat.sort()
        n = len(flat)
        median = flat[n // 2]
        return sum(abs(v - median) // x for v in flat)

