var minOperations = function(grid, x) {
    const flat = [];
    for (const row of grid) for (const v of row) flat.push(v);
    const r0 = flat[0] % x;
    for (const v of flat) {
        if (v % x !== r0) return -1;
    }
    flat.sort((a, b) => a - b);
    const n = flat.length;
    const median = flat[Math.floor(n / 2)];
    let ops = 0;
    for (const v of flat) ops += Math.abs(v - median) / x;
    return ops;
};
